#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *A = (int*)malloc((N+1)*sizeof(int));
        for (int i = 1; i <= N; ++i) scanf("%d", &A[i]);
        if (N == 1) { printf("0\n"); free(A); continue; }
        if (A[1] == 0) { printf("-1\n"); free(A); continue; }
        int jumps = 0, currentEnd = 1, farthest = 1;
        int possible = 1;
        for (int i = 1; i < N; ++i) {
            if (i + A[i] > farthest) farthest = i + A[i];
            if (i == currentEnd) {
                jumps++;
                if (farthest <= i) { possible = 0; break; }
                currentEnd = farthest;
                if (currentEnd >= N) break;
            }
        }
        if (!possible || currentEnd < N) printf("-1\n");
        else printf("%d\n", jumps);
        free(A);
    }
    return 0;
}

