import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] A = new int[N + 1];
            for (int i = 1; i <= N; i++) A[i] = fs.nextInt();
            if (N == 1) {
                sb.append(0).append('\n');
                continue;
            }
            if (A[1] == 0) {
                sb.append(-1).append('\n');
                continue;
            }
            int jumps = 0, currentEnd = 1, farthest = 1;
            boolean possible = true;
            for (int i = 1; i < N; i++) {
                farthest = Math.max(farthest, i + A[i]);
                if (i == currentEnd) {
                    jumps++;
                    if (farthest <= i) { possible = false; break; }
                    currentEnd = farthest;
                    if (currentEnd >= N) break;
                }
            }
            if (!possible || currentEnd < N) sb.append(-1).append('\n');
            else sb.append(jumps).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for competitive programming
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

