#!/usr/bin/env python3
import sys

def min_jumps(arr):
    n = len(arr) - 1  # arr is 1‑based
    if n == 1:
        return 0
    if arr[1] == 0:
        return -1
    jumps = 0
    current_end = 1
    farthest = 1
    for i in range(1, n):
        farthest = max(farthest, i + arr[i])
        if i == current_end:
            jumps += 1
            if farthest <= i:
                return -1
            current_end = farthest
            if current_end >= n:
                break
    return jumps if current_end >= n else -1


def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [0] + [int(next(it)) for _ in range(n)]
        out_lines.append(str(min_jumps(a)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

